# @cctt_verify {"v":2,"sym":"sympy.physics.quantum.tests.test_cartesian.test_x","kind":"function","src_hash":"604656b4ee8c44be","in":{"base":"Any"},"out":{"base":"Any","pred":"X.hilbert_space == L2(Interval(S.NegativeInfinity, S.Infinity)) and Commutator(X, Px).doit() == I * hbar and qapply(X * XKet(x)) == x * XKet(x) and XKet(x).dual_class() == XBra and XBra(x).dual_class() == XKet and (Dagger(XKet(y)) * XKet(x)).doit() == DiracDelta(x - y) and (PxBra(px) * XKet(x)).doit() == exp(-I * x * px / hbar) / sqrt(2 * pi * hbar) and represent(XKet(x)) == DiracDelta(x - x_1) and represent(XBra(x)) == DiracDelta(-x + x_1) and XBra(x).position == x and represent(XOp() * XKet()) == x * DiracDelta(x - x_2) and represent(XBra('y') * XKet()) == DiracDelta(x - y) and represent(XKet() * XBra()) == DiracDelta(x - x_2) * DiracDelta(x_1 - x) and rep_p == hbar * I * DiracDelta(px_1 - px_2) * DifferentialOperator(px_1) and rep_p == represent(XOp(), basis=PxOp()) and rep_p == represent(XOp(), basis=PxKet) and rep_p == represent(XOp(), basis=PxKet())"},"spec":{"lhs":"test_x()","rhs":"test_x produces the expected output","over":{"base":"Any"},"name":"test_x_correct"},"guarantee":"test_x produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.physics.quantum.tests.test_cartesian.test_x_correct","statement":"Path(test_x(x), test_x produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"eecb9e383c35a4e8"}
def test_x():
    assert X.hilbert_space == L2(Interval(S.NegativeInfinity, S.Infinity))
    assert Commutator(X, Px).doit() == I*hbar
    assert qapply(X*XKet(x)) == x*XKet(x)
    assert XKet(x).dual_class() == XBra
    assert XBra(x).dual_class() == XKet
    assert (Dagger(XKet(y))*XKet(x)).doit() == DiracDelta(x - y)
    assert (PxBra(px)*XKet(x)).doit() == \
        exp(-I*x*px/hbar)/sqrt(2*pi*hbar)
    assert represent(XKet(x)) == DiracDelta(x - x_1)
    assert represent(XBra(x)) == DiracDelta(-x + x_1)
    assert XBra(x).position == x
    assert represent(XOp()*XKet()) == x*DiracDelta(x - x_2)
    assert represent(XBra("y")*XKet()) == DiracDelta(x - y)
    assert represent(
        XKet()*XBra()) == DiracDelta(x - x_2) * DiracDelta(x_1 - x)

    rep_p = represent(XOp(), basis=PxOp)
    assert rep_p == hbar*I*DiracDelta(px_1 - px_2)*DifferentialOperator(px_1)
    assert rep_p == represent(XOp(), basis=PxOp())
    assert rep_p == represent(XOp(), basis=PxKet)
    assert rep_p == represent(XOp(), basis=PxKet())

    assert represent(XOp()*PxKet(), basis=PxKet) == \
        hbar*I*DiracDelta(px - px_2)*DifferentialOperator(px)


